import static org.junit.jupiter.api.Assertions.*;
public class Jsoup_parse_0_Test {
    @Test
    @DisplayName("parse(String html, String baseUri) with non-empty html and baseUri returns Document with correct text and absolute links")
    void test_TC01_O1() {
        String html = "<a href='page.html'>Hello World</a>";
        String baseUri = "http://example.com/dir/";
        Document doc = Jsoup.parse(html, baseUri);
        assertAll(
            () -> assertEquals("Hello World", doc.body().text()),
            () -> assertEquals("http://example.com/dir/page.html",
                              doc.select("a").first().absUrl("href"))
        );
    }

    @Test
    @DisplayName("parse(String html, String baseUri) with empty html returns empty body Document")
    void test_TC02_O1() {
        String html = "";
        String baseUri = "http://example.com";
        Document doc = Jsoup.parse(html, baseUri);
        assertEquals("", doc.body().html());
    }

    @Test
    @DisplayName("parse(String html) delegates to parse(html,\"") yielding empty baseUri Document")
    void test_TC03_O2() {
        String html = "<p>Hello</p>";
        Document doc = Jsoup.parse(html);
        assertEquals("Hello", doc.body().text());
    }

    @Test
    @DisplayName("parse(String html, Parser parser) with xmlParser returns Document from parser")
    void test_TC04_O3() {
        String html = "<tag/>";
        Parser xml = Parser.xmlParser();
        Document doc = Jsoup.parse(html, xml);
        assertEquals("<tag />", doc.body().html());
    }

    @Test
    @DisplayName("parse(String html, String baseUri, Parser parser) with html containing base tag uses parser and resolves baseUri")
    void test_TC05_O4() {
        String html = "<base href='http://override/'><a href='x'>X</a>";
        String baseUri = "http://ignored/";
        Parser parser = Parser.htmlParser();
        Document doc = Jsoup.parse(html, baseUri, parser);
        assertAll(
            () -> assertEquals("http://override/", doc.select("base").attr("href")),
            () -> assertEquals("http://override/x", doc.select("a").first().absUrl("href"))
        );
    }

    @Test
    @DisplayName("parse(File file, charsetName, baseUri) loads file via DataUtil and returns Document")
    void test_TC06_O5() throws IOException {
        File tmp = File.createTempFile("jsoupTest", ".html");
        tmp.deleteOnExit();
        try (FileWriter fw = new FileWriter(tmp)) {
            fw.write("<p>F</p>");
        }
        String charset = "UTF-8";
        String baseUri = "http://b/";
        Document doc = Jsoup.parse(tmp, charset, baseUri);
        assertEquals("F", doc.body().text());
    }

    @Test
    @DisplayName("parse(File file) default charsetName null loads using BOM/meta and returns Document")
    void test_TC07_O5() throws IOException {
        File tmp = File.createTempFile("jsoupTest", ".html");
        tmp.deleteOnExit();
        try (FileWriter fw = new FileWriter(tmp)) {
            fw.write("<p>N</p>");
        }
        Document doc = Jsoup.parse(tmp);
        assertEquals("N", doc.body().text());
    }

    @Test
    @DisplayName("parse(InputStream in, charsetName, baseUri) throws IOException when stream invalid")
    void test_TC08_O6() {
        InputStream bad = new InputStream() {
            @Override
            public int read() throws IOException {
                throw new IOException("read error");
            }
        };
        assertThrows(IOException.class, () -> Jsoup.parse(bad, "UTF-8", "http://x"));
    }

    @Test
    @DisplayName("parse(URL url, timeoutMillis) with valid http URL and small timeout returns Document")
    void test_TC09_O7() throws Exception {
        com.sun.net.httpserver.HttpServer server =
            com.sun.net.httpserver.HttpServer.create(new InetSocketAddress(0), 0);
        server.createContext("/", exch -> {
            byte[] resp = "<p>S</p>".getBytes("UTF-8");
            exch.sendResponseHeaders(200, resp.length);
            exch.getResponseBody().write(resp);
            exch.close();
        });
        server.setExecutor(Executors.newSingleThreadExecutor());
        server.start();
        try {
            URL url = new URL("http://127.0.0.1:" + server.getAddress().getPort() + "/");
            Document doc = Jsoup.parse(url, 1000);
            assertEquals("S", doc.body().text());
        } finally {
            server.stop(0);
        }
    }

    @Test
    @DisplayName("parse(URL url, timeoutMillis) throws java.net.MalformedURLException for non-http URL")
    void test_TC10_O7() throws Exception {
        URL ftpUrl = new URL("ftp://example.com");
        assertThrows(MalformedURLException.class, () -> Jsoup.parse(ftpUrl, 1000));
    }
}
